// components/fields/FileUploader.tsx

import React from 'react';
import {type FieldValues, useFormContext} from 'react-hook-form';
import {KitsFilePicker} from "../../../../_compat";
import type {IFile, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';

/**
 * Renders a file or image uploader.
 * It uses useFieldLogic for standard field state and useFormContext for form-level
 * configurations like outputFormat and error handling.
 */
export const FileUploader = <T extends FieldValues>({
                                                        element,
                                                        control,
                                                        getValues,
                                                        fieldLogic,
                                                    }: UseFieldLogicElementProps<T>) => {

    // 1. Get form-level context for special properties.
    // We need to know the outputFormat to correctly structure the onChange payload.
    // We also need setError and clearErrors for the custom onError handler.
    const {setError, clearErrors, getValues: getFormConfig} = useFormContext();
    const outputFormat = (getFormConfig() as any).outputFormat || 'Json'; // Get form's output format

    // 2. Get field-level state and props from the central logic hook.
    const {
        field,
        fieldState,
        label,
        isDisabled,
        isRequired,
        helperText,
        placeholder,
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    // 3. Cast the element to its specific type to access unique properties.
    const fileElement = element as IFile<T>;
    const {
        type,
        multiple,
        limit,
        acceptedTypes,
        maxFileSize,
        minFileSize,
        classicUploader,
        children,
    } = fileElement;

    // 4. Define the specific handlers for this component.
    const handleOnChange = (files: File[], base64Data: any[]) => {
        if (outputFormat === 'FormData') {
            field.onChange(multiple ? files : files[0]);
        } else {
            field.onChange(multiple ? base64Data : base64Data[0]);
        }
    };

    const handleError = (errorMessage: string) => {
        if (errorMessage === 'clear') {
            clearErrors(field.name);
        } else {
            setError(field.name, {type: 'custom', message: errorMessage});
        }
    };

    // 5. Render the "dumb" UI component with the resolved props.
    return (
        <KitsFilePicker
            id={field.name}
            value={field.value}
            //@ts-ignore
            onChange={handleOnChange}
            onError={handleError}

            // --- Resolved props ---
            label={label}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            placeholder={placeholder}
            attached={attached}

            // --- Props from element definition ---
            type={type}
            multiple={multiple}
            limit={limit}
            acceptedTypes={acceptedTypes}
            maxFileSize={maxFileSize}
            minFileSize={minFileSize}
            classicUploader={classicUploader}
            isJsonOutput={outputFormat === 'Json'}
            children={children}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}
        />
    );
};

export default FileUploader;
